"use strict";(self.webpackChunkrbg_website=self.webpackChunkrbg_website||[]).push([[4031],{4108:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/04/01/v0.7.0-alpha.2","metadata":{"permalink":"/blog/2026/04/01/v0.7.0-alpha.2","source":"@site/blog/2026-04-01-v0.7.0-alpha.2.md","title":"RBG v0.7.0-alpha.2 Released","description":"We\'re excited to announce the release of RBG v0.7.0-alpha.2!","date":"2026-04-01T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/blog/tags/release"},{"inline":true,"label":"alpha","permalink":"/blog/tags/alpha"}],"readingTime":0.28,"hasTruncateMarker":false,"authors":[{"name":"SGLang Team","title":"RBG Contributors","url":"https://github.com/sgl-project","imageURL":"https://avatars.githubusercontent.com/u/147780389?v=4","key":"sglang","page":null}],"frontMatter":{"title":"RBG v0.7.0-alpha.2 Released","authors":["sglang"],"tags":["release","alpha"]},"unlisted":false,"nextItem":{"title":"RBG v0.4.0 Released","permalink":"/blog/2025/09/23/v0.4.0"}},"content":"We\'re excited to announce the release of RBG v0.7.0-alpha.2!\\n\\n## What\'s New\\n\\nThis alpha release includes several improvements and new features. Please check out the [release notes](https://github.com/sgl-project/rbg/releases/tag/v0.7.0-alpha.2) for more details.\\n\\n## Getting Started\\n\\nInstall the latest version:\\n\\n```bash\\nkubectl apply --server-side -f https://github.com/sgl-project/rbg/releases/download/v0.7.0-alpha.2/manifests.yaml\\n```\\n\\n## Feedback\\n\\nWe welcome your feedback! Please report any issues on [GitHub](https://github.com/sgl-project/rbg/issues)."},{"id":"/2025/09/23/v0.4.0","metadata":{"permalink":"/blog/2025/09/23/v0.4.0","source":"@site/blog/2025-09-23-v0.4.0.md","title":"RBG v0.4.0 Released","description":"We\'re excited to announce the release of RBG v0.4.0!","date":"2025-09-23T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/blog/tags/release"}],"readingTime":0.285,"hasTruncateMarker":false,"authors":[{"name":"SGLang Team","title":"RBG Contributors","url":"https://github.com/sgl-project","imageURL":"https://avatars.githubusercontent.com/u/147780389?v=4","key":"sglang","page":null}],"frontMatter":{"title":"RBG v0.4.0 Released","authors":["sglang"],"tags":["release"]},"unlisted":false,"prevItem":{"title":"RBG v0.7.0-alpha.2 Released","permalink":"/blog/2026/04/01/v0.7.0-alpha.2"},"nextItem":{"title":"Introducing RoleBasedGroup","permalink":"/blog/2025/08/28/introducing-rbg"}},"content":"We\'re excited to announce the release of RBG v0.4.0!\\n\\n## Key Features\\n\\nThis release includes:\\n- Improved multi-role coordination\\n- Enhanced autoscaling support\\n- Better failure handling mechanisms\\n\\nCheck out the [release notes](https://github.com/sgl-project/rbg/releases/tag/v0.4.0) for complete details.\\n\\n## Version Compatibility\\n\\n| RBG Version | Kubernetes Version | LeaderWorkerSet Version |\\n|:-----------:|:------------------:|:-----------------------:|\\n|   v0.4.0    |     >=v1.28.x      |        >=v0.7.0         |"},{"id":"/2025/08/28/introducing-rbg","metadata":{"permalink":"/blog/2025/08/28/introducing-rbg","source":"@site/blog/2025-08-28-introducing-rbg.md","title":"Introducing RoleBasedGroup","description":"RoleBasedGroup (RBG) is a Kubernetes API for orchestrating distributed, stateful AI inference workloads.","date":"2025-08-28T00:00:00.000Z","tags":[{"inline":true,"label":"announcement","permalink":"/blog/tags/announcement"}],"readingTime":0.58,"hasTruncateMarker":false,"authors":[{"name":"SGLang Team","title":"RBG Contributors","url":"https://github.com/sgl-project","imageURL":"https://avatars.githubusercontent.com/u/147780389?v=4","key":"sglang","page":null}],"frontMatter":{"title":"Introducing RoleBasedGroup","authors":["sglang"],"tags":["announcement"]},"unlisted":false,"prevItem":{"title":"RBG v0.4.0 Released","permalink":"/blog/2025/09/23/v0.4.0"}},"content":"RoleBasedGroup (RBG) is a Kubernetes API for orchestrating distributed, stateful AI inference workloads.\\n\\n## Why RBG?\\n\\nTraditional Kubernetes primitives are ill-suited for LLM inference services that:\\n- Run as multi-role topologies (gateway/router/prefill/decode)\\n- Are performance-sensitive to GPU/network topology\\n- Require atomic, cross-role operations\\n\\nRBG treats an inference service as a **role-based group**, managing it as a single coordinated unit.\\n\\n## The SCOPE Framework\\n\\nRBG provides five core capabilities:\\n\\n- **Stable** - Topology-aware deterministic operations\\n- **Coordination** - Cross-role policy engine\\n- **Orchestration** - Role dependencies and startup sequences\\n- **Performance** - Topology-aware placement\\n- **Extensible** - Future-proof deployment abstraction\\n\\n## Getting Started\\n\\nCheck out our [Quick Start Guide](/docs/quick_start) to begin deploying LLM inference services with RBG."}]}}')}}]);